def stripe_dcf(revenue_start, growth_rates, fcf_margin, wacc, tgr):
    """Build a DCF and return intrinsic enterprise value."""
    fcfs, pvs = [], []
    rev = revenue_start
    for t, g in enumerate(growth_rates, 1):
        rev *= (1 + g)
        fcf = rev * fcf_margin
        pv  = fcf / (1 + wacc) ** t
        fcfs.append(fcf)
        pvs.append(pv)
    terminal_fcf = fcfs[-1] * (1 + tgr)
    tv  = terminal_fcf / (wacc - tgr)
    tv_pv = tv / (1 + wacc) ** len(growth_rates)
    return sum(pvs) + tv_pv

scenarios = {
    'Bear': {
        'growth_rates': [0.15, 0.12, 0.10, 0.09, 0.08],
        'fcf_margin': 0.12, 'wacc': 0.13, 'tgr': 0.03
    },
    'Base': {
        'growth_rates': [0.24, 0.20, 0.17, 0.14, 0.12],
        'fcf_margin': 0.16, 'wacc': 0.11, 'tgr': 0.04
    },
    'Bull': {
        'growth_rates': [0.30, 0.26, 0.22, 0.18, 0.15],
        'fcf_margin': 0.20, 'wacc': 0.10, 'tgr': 0.05
    }
}

print("=== THREE-SCENARIO DCF ===")
for name, params in scenarios.items():
    val = stripe_dcf(4.8, **params)
    vs_ipo = val / 85 - 1
    print(f"{name}: ${val:.1f}B  ({vs_ipo:+.0%} vs $85B IPO price)")

# Sensitivity table: WACC vs terminal growth rate (Base case growth)
print("\n=== SENSITIVITY: Intrinsic Value ($B) ===")
print("WACC \\ TGR    3.0%    3.5%    4.0%    4.5%    5.0%")
print("-" * 52)
for wacc in [0.09, 0.10, 0.11, 0.12, 0.13]:
    row = f"{wacc:.0%}       "
    for tgr in [0.03, 0.035, 0.04, 0.045, 0.05]:
        if tgr >= wacc:
            row += "  n/a  "
        else:
            val = stripe_dcf(4.8, [0.24,0.20,0.17,0.14,0.12], 0.16, wacc, tgr)
            row += f"  {val:>5.0f}"
    print(row)
